#define COMMON_VDB_READ
          
static STATUS ReadVdbWindow(U8 ModuleState)
{
   STATUS Status = OS_SUCCESS;

   if (ModuleState >= APP_INIT3)
   {
      READ_VDB_ARRAY( P_LCNV_GenCnv_MaxTorque,                  Status);
      READ_VDB_ARRAY( P_LCNV_MaxPowerSP,                        Status);
   }         
   return Status;
}

#define COMMON_VDB_WRITE
          
static STATUS WriteVdbWindow(U8 ModuleState)
{
   STATUS Status = OS_SUCCESS;
   WRITE_VDB_ARRAY(V_LCNV_GS1_StatusLog,                     Status);
   WRITE_VDB_ARRAY(V_LCNV_MS1_StatusLog,                     Status);
   WRITE_VDB_ARRAY(V_LCNV_MS2_StatusLog,                     Status);
   WRITE_VDB_ARRAY(V_LCNV_MS3_StatusLog,                     Status);
   WRITE_VDB_ARRAY(V_LCNV_MS4_StatusLog,                     Status);
   WRITE_VDB_ARRAY(V_LCNV_EX_StatusLog,                      Status);
   WRITE_VDB_ARRAY(V_LCNV_StatusLog,                         Status);
   return Status;
}


