// Grid converter Control Word
typedef union
{
    U16 Value;
    struct
    {
        U16
            Enable : 1,             // enable/disable converter
            Connect : 1,            // connect grid
            PWM_Start : 1,          // start PWM switching
            ParameterSet : 1,       // change parameter set used in converter
            ControlMode_bit1 : 1,   // 
            ControlMode_bit2 : 1,   //
            
            Reserve_01 : 1,   // not used
            Reserve_02 : 1,   // not used
            Reserve_03 : 1,   // not used
            Reserve_04 : 1,   // not used
            Reserve_05 : 1,   // not used
            Reserve_06 : 1,   // not used
            Reserve_07 : 1,   // not used
            Reserve_08 : 1,   // not used
            Reserve_09 : 1,   // not used
            Reserve_10 : 1;   // not used
    };
} GRID_ControlWord_t;

// Grid converter Control Data
typedef struct
{
    S16 ReactivePowerRef;
} GRID_ControlData_t;

// Grid converter Status Word
typedef union
{
    U16 Value;
    struct
    {
        U16
            Ready : 1,
            Fault : 1,
            Warning : 1,
            Grid_OK : 1,
            Connected : 1,
            PWM_Running : 1,
            SelfDiagnosticActive : 1,
            ActiveParameterSet : 1,

            Reserve_01 : 1, // not used
            Reserve_02 : 1, // not used
            Reserve_03 : 1, // not used
            Reserve_04 : 1, // not used
            Reserve_05 : 1, // not used
            Reserve_06 : 1, // not used
            Reserve_07 : 1, // not used
            
            FRT_Detected : 1;          // bit is set TRUE when FRT condition is active
    };
} GRID_StatusWord_t;

