static STATUS Initialize()
{
    STATUS LocalStatus = 0;
    
#if defined DLL_SIMU

    LocalStatus = OS_VarDB_GetVariableID("DLL_OUT_GenConnected", &DLL_OUT_GenConnected_ID);
    if (LocalStatus != 0)
    {
        return -200;
    }

    pwrSPavgFilt = FilterAvg_New(5/*avgCount*/, 500/*avgPeriod*/, LCNV_SCAN_TIME/*timeStep*/);
    if (pwrSPavgFilt == NULL)
    {
        return -201;
    }

#endif

#ifndef DLL_SIMU
    Initialize_CommData();
#endif

    // set converters safety chain input relay bypass outputs
    DO_LCNV_SafetyBypass_2 = true;
    DO_LCNV_SafetyBypass_3 = true;
    DO_LCNV_SafetyBypass_4 = true;
    
    // Initialize converter control algorithm selection
    switch (P_LCNV_ControlAlgorithm)
    {
        case LCNV_POWER_CONTROL:

            ControlAlgorithm = LCNV_POWER_CONTROL;
            break;

        case LCNV_TORQUE_CONTROL:

            ControlAlgorithm = LCNV_TORQUE_CONTROL;
            break;

        default:

            // if "P_LCNV_ControlAlgorithm" has wrong value then automatically switch to Power Control algorithm
            P_LCNV_ControlAlgorithm = LCNV_POWER_CONTROL;
            OS_VarDB_UpdateVariableByName("P_LCNV_ControlAlgorithm", &P_LCNV_ControlAlgorithm, sizeof(P_LCNV_ControlAlgorithm));
            ControlAlgorithm = LCNV_POWER_CONTROL;
            break;
    }
    /*
    // load power correction tables
    if (P_LCNV_PwrSPCorrCnv_Enable)
    {
        LoadCorrectionTable_Cnv();
    }
    if (P_LCNV_PwrSPCorrGen_Enable)
    {
        LoadCorrectionTable_Gen();
    }
    */

    //ClearCorrLearnMemory();

    PwrSPCorr_PI = PI_New_3(0/*KpInc*/, 0/*KpDec*/, 0/*KiInc*/, 0/*KiDec*/, -5000/*Min--500kW*/, 5000/*Max-500kW*/, 500/*RateInc*/, 500/*RateDec*/, 1000/*TimeBase*/, LCNV_SCAN_TIME/*TimeStep*/);
    PowerSP_RateLim = RateLim_New(1500/*RateUp*/, 1500/*RateDown*/, 1000/*TimeBase*/, LCNV_SCAN_TIME/*TimeStep*/);
    ReactPowerSP_RateLim = RateLim_New(500/*RateUp*/, 500/*RateDown*/, 1000/*TimeBase*/, LCNV_SCAN_TIME/*TimeStep*/);
    PwrSPCorrCnv_RateLim = RateLim_New(50/*RateUp-5kW*/, 150/*RateDown-15kW*/, 1000/*TimeBase*/, LCNV_SCAN_TIME/*TimeStep*/);
    PwrSPCorrCnv_Hyst = HystUpDown_New(150/*hysteresis-15kW*/, -5000/*low_Limit- -500kW*/, 5000/*high_Limit- 500kW*/);
    Excitation_RateLim = RateLim_New(30/*RateUp*/, 30/*RateDown*/, 1000/*TimeBase*/, LCNV_SCAN_TIME/*TimeStep*/);

    LocalStatus = Load_Parameters();
    if (LocalStatus != 0)
    {
        OS_com_printf("Error loading \"FeCon Converter\" parameters (%d)", LocalStatus);
        return LocalStatus;
    }
    LocalStatus = Load_PI_Parameters();
    if (LocalStatus != 0)
    {
        OS_com_printf("Error loading \"FeCon Converter\" PI parameters (%d)", LocalStatus);
        return LocalStatus;
    }

    Converter.Excitation.ControlWord.Enable = true;

    return LocalStatus;

    //#endif
}


