//***********************************************************************
// STATE : Not Ready
//***********************************************************************
static void CNV_NotReady_State(S32 callMode)
{
    //-----------------------------------------------------------------------
    //ENTRY ACTION
    //-----------------------------------------------------------------------
    if (callMode == LCNV_STATE_CALLMODE_INIT)
    {
        strcpy(V_CNV_StateTxt, "Not Ready");
        V_CNV_State = CNV_NOT_READY;
        V_LCNV_State_SubStep = 0;
        Converter.Excitation.ControlWord.Enable = true;
    }

    //-----------------------------------------------------------------------
    //CONTROL
    //-----------------------------------------------------------------------
    switch (V_LCNV_State_SubStep)
    {
        case 0:
        {
            V_LCNV_State_SubStep = 1;
            break;
        }
    }

    //-----------------------------------------------------------------------
    // EXIT CONDITIONS
    //-----------------------------------------------------------------------
    if (V_CNV_RequestedState == CNV_EM_STOP)
    {
        StateFunctionPointer = CNV_EmStop_State;
    }
    else if (!GridCnvEnabled_Count || !GenCnvEnabled_Count)
    {
        StateFunctionPointer = CNV_Disabled_State;
    }
    else if (CnvFault_Count)
    {
        StateFunctionPointer = CNV_Fault_State;
    }
    else if (!NotReady_Count)
    {
        StateFunctionPointer = CNV_ReadyToStart_State;
    }
}




//***********************************************************************
// STATE : Fault
//***********************************************************************
static void CNV_Fault_State(S32 callMode)
{
    static U8 step;

    //-----------------------------------------------------------------------
    //ENTRY ACTION
    //-----------------------------------------------------------------------
    if (callMode == LCNV_STATE_CALLMODE_INIT)
    {
        V_CNV_State = CNV_FAULT;
        strcpy(V_CNV_StateTxt, "Converter Fault");
        V_LCNV_State_SubStep = 0;
        StopAll();
    }


    //-----------------------------------------------------------------------
    //CONTROL
    //-----------------------------------------------------------------------
    ResetHandler(false);    // auto reset


    //-----------------------------------------------------------------------
    // EXIT CONDITIONS
    //-----------------------------------------------------------------------
    if (!GridCnvEnabled_Count || !GenCnvEnabled_Count)
    {
        StateFunctionPointer = CNV_Disabled_State;
    }
    else if (!CnvFault_Count)
    {
        if (NotReady_Count)
        {
            StateFunctionPointer = CNV_NotReady_State;
        }
        else
        {
            StateFunctionPointer = CNV_ReadyToStart_State;
        }
    }
}




//***********************************************************************
