//***********************************************************************
// STATE : Disconnecting grid
//***********************************************************************
static void CNV_Grid_Disconnecting_State(S32 callMode)
{
    static int timer;

    //-----------------------------------------------------------------------
    //ENTRY ACTION
    //-----------------------------------------------------------------------
    if (callMode == LCNV_STATE_CALLMODE_INIT)
    {
        V_CNV_State = CNV_GRID_DISCONNECTING;
        V_LCNV_State_SubStep = 0;
        strcpy(V_CNV_StateTxt, "Disconnecting Grid");
        timer = 4000;   // disconnecting timeout 4s
    }

    //-----------------------------------------------------------------------
    //CONTROL
    //-----------------------------------------------------------------------
    switch (V_LCNV_State_SubStep)
    {
        case 0:
        {
            Converter.GridConverter[0].ControlWord.Connect = false;
            V_LCNV_State_SubStep = 1;
            break;
        }
        case 1:
        {
            if (!Converter.GridConverter[0].StatusWord.Connected)
            {
                StateFunctionPointer = CNV_ReadyToStart_State;  // go to next state
            }
            break;
        }
    }

    //-----------------------------------------------------------------------
    // EXIT CONDITIONS
    //-----------------------------------------------------------------------
    timer -= LCNV_SCAN_TIME;

    if (V_CNV_RequestedState == CNV_EM_STOP)
    {
        StateFunctionPointer = CNV_EmStop_State;
    }
    else if (timer <= 0)
    {
        ProcessTimeout_Flag = true;
        StateFunctionPointer = CNV_Fault_State;
    }
    else if (CnvFault_Count)
    {
        StateFunctionPointer = CNV_Fault_State;
    }
    else if (NotReady_Count)
    {
        StateFunctionPointer = CNV_NotReady_State;
    }
}




