//***********************************************************************
// STATE : Stopping grid
//***********************************************************************
static void CNV_Grid_Stopping_State(S32 callMode)
{
    static int timer;

    //-----------------------------------------------------------------------
    //ENTRY ACTION
    //-----------------------------------------------------------------------
    if (callMode == LCNV_STATE_CALLMODE_INIT)
    {
        V_CNV_State = CNV_GRID_STOPPING;
        V_LCNV_State_SubStep = 0;
        strcpy(V_CNV_StateTxt, "Grid Stopping");
        timer = P_LCNV_StopTimeout;
    }

    //-----------------------------------------------------------------------
    //CONTROL
    //-----------------------------------------------------------------------
    switch (V_LCNV_State_SubStep)
    {
        case 0:  // ramp down reactive power command
        {
            Converter.GridConverter[0].ControlData.ReactivePowerRef = RateLim_Control(ReactPowerSP_RateLim, 0);
            if (Converter.GridConverter[0].ControlData.ReactivePowerRef == 0)
            {
                V_LCNV_State_SubStep = 1;
            }
            break;
        }
        case 1:  // stop PWM
        {
            Converter.GridConverter[0].ControlWord.PWM_Start = false;
            V_LCNV_State_SubStep = 2;
            break;
        }
        case 2:  // stopping PWM
        {
            if (!Converter.GridConverter[0].StatusWord.PWM_Running)
            {
                StateFunctionPointer = CNV_Grid_Connected_State;  // grid stopped
            }
            break;
        }
    }

    //-----------------------------------------------------------------------
    // EXIT CONDITIONS
    //-----------------------------------------------------------------------
    timer -= LCNV_SCAN_TIME;

    if (V_CNV_RequestedState == CNV_EM_STOP)
    {
        StateFunctionPointer = CNV_EmStop_State;
    }
    else if (timer <= 0)
    {
        ProcessTimeout_Flag = true;
        StateFunctionPointer = CNV_Fault_State;
    }
    else if (CnvFault_Count)
    {
        StateFunctionPointer = CNV_Fault_State;
    }
    else if (NotReady_Count)
    {
        StateFunctionPointer = CNV_NotReady_State;
    }
}




