//***********************************************************************
// STATE : Stop generator
//***********************************************************************
static void CNV_Gen_Stopping_State(S32 callMode)
{
    static int timer;
    
    //-----------------------------------------------------------------------
    //ENTRY ACTION
    //-----------------------------------------------------------------------
    if (callMode == LCNV_STATE_CALLMODE_INIT)
    {
        V_CNV_State = CNV_GEN_STOPPING;
        V_LCNV_State_SubStep = 0;
        strcpy(V_CNV_StateTxt, "Stopping Generator");
        
        timer = P_LCNV_StopTimeout;
        PI_Reset_3(PwrSPCorr_PI);      // always reset power setpoint correction PID after operation
    }

    //-----------------------------------------------------------------------
    //CONTROL
    //-----------------------------------------------------------------------
    S32 setpoint;
    
    switch (V_LCNV_State_SubStep)
    {
        case 0:  // ramping down active power reference
        {
            // active power ref
            setpoint = RateLim_Control(PowerSP_RateLim, 0);
            setpoint = setpoint / GenCnvEnabled_Count;
            
            if (setpoint == 0)
            {
                V_LCNV_State_SubStep = 1;
            }
            else
            {
                int i;
                for(i = 0; i < LCNV_GENCNV_CNT; i++)
                {
                    if (Converter.GenConverter[i].ControlWord.Enable)
                    {
                        Converter.GenConverter[i].ControlData.ControlRef = setpoint;
                    }
                }
            }
            
            UpdateExcitationCommand(false);
            break;
        }
        case 1:  // ramping down excitation
        {
            //first ramp excitation to min current
            Converter.Excitation.ControlData.ExcitationCurrentRef = RateLim_Control(Excitation_RateLim, P_LCNV_ExciterMinCurrent);
            V_CNV_PowerSetpoint = 0;
            UpdateGenCommand(false);
            
            if (Converter.GenConverter[0].ControlData.ControlRef <= 0 &&
                Converter.GenConverter[1].ControlData.ControlRef <= 0 &&
                Converter.GenConverter[2].ControlData.ControlRef <= 0 &&
                Converter.GenConverter[3].ControlData.ControlRef <= 0 &&
                Converter.Excitation.ControlData.ExcitationCurrentRef <= P_LCNV_ExciterMinCurrent)
            {
                V_LCNV_State_SubStep = 2;
            }
            break;
        }
        case 2:  // checking actual values
        {
            if (Converter.Excitation.StatusData.Current <= (P_LCNV_ExciterMinCurrent + 5))
            {
                V_LCNV_State_SubStep = 3;
            }
            break;
        }
        case 3:  // stopping
        {
            Converter.GenConverter[0].ControlWord.PWM_Start = false;
            Converter.GenConverter[1].ControlWord.PWM_Start = false;
            Converter.GenConverter[2].ControlWord.PWM_Start = false;
            Converter.GenConverter[3].ControlWord.PWM_Start = false;
            V_LCNV_State_SubStep = 4;
            break;
        }
        case 4:
        {
            if (!Converter.GenConverter[0].StatusWord.PWM_Running &&
                !Converter.GenConverter[1].StatusWord.PWM_Running &&
                !Converter.GenConverter[2].StatusWord.PWM_Running &&
                !Converter.GenConverter[3].StatusWord.PWM_Running)
            {
                V_LCNV_State_SubStep = 5;
            }
            break;
        }
        case 5:  // stop excitation
        {
            Converter.Excitation.ControlData.ExcitationCurrentRef = RateLim_Control(Excitation_RateLim, 0);
            
            if (Converter.Excitation.ControlData.ExcitationCurrentRef <= P_LCNV_ExciterCurrentZero &&
                Converter.Excitation.StatusData.Current <= P_LCNV_ExciterCurrentZero)
            {
                Converter.Excitation.ControlData.ExcitationCurrentRef = 0;
                Converter.Excitation.ControlWord.PWM_Start = false;
                V_LCNV_State_SubStep = 6;
            }
            break;
        }
        case 6:  // stopping excitation
        {
            if (!Converter.Excitation.StatusWord.PWM_Running)
            {
                StateFunctionPointer = CNV_Grid_Running_State;  // gen stopped
            }
            break;
        }
    }
    
    
    UpdateGridCommand(false);

    //-----------------------------------------------------------------------
    // EXIT CONDITIONS
    //-----------------------------------------------------------------------
    timer -= LCNV_SCAN_TIME;

    if (V_CNV_RequestedState == CNV_EM_STOP)
    {
        StateFunctionPointer = CNV_EmStop_State;
    }
    else if (timer <= 0)
    {
        ProcessTimeout_Flag = true;
        StateFunctionPointer = CNV_Fault_State;
    }
    else if (CnvFault_Count)
    {
        StateFunctionPointer = CNV_Fault_State;
    }
    else if (NotReady_Count)
    {
        StateFunctionPointer = CNV_NotReady_State;
    }
}




//***********************************************************************
// STATE : Starting generator
//***********************************************************************
static void CNV_Gen_Starting_State(S32 callMode)
{
    static int timer;
    int i;

    //-----------------------------------------------------------------------
    //ENTRY ACTION
    //-----------------------------------------------------------------------
    if (callMode == LCNV_STATE_CALLMODE_INIT)
    {
        V_CNV_State = CNV_GEN_STARTING;
        V_LCNV_State_SubStep = 0;
        strcpy(V_CNV_StateTxt, "Start Generator");
        
        timer = P_LCNV_StartMachineTimeout;
        UpdateGenCommand(true);
        UpdateExcitationCommand(true);
    }

    //-----------------------------------------------------------------------
    //CONTROL
    //-----------------------------------------------------------------------
    switch (V_LCNV_State_SubStep)
    {
        case 0:  // start excitation
        {
            Converter.Excitation.ControlWord.Enable = true;
            Converter.Excitation.ControlWord.PWM_Start = true;
            V_LCNV_State_SubStep = 1;
            break;
        }
        case 1:  // starting excitation
        {
            if (Converter.Excitation.StatusWord.PWM_Running == true)
            {
                V_LCNV_State_SubStep = 2;
            }
            break;
        }
        case 2:  // ramp up excitation
        {
            Converter.Excitation.ControlData.ExcitationCurrentRef = RateLim_Control(Excitation_RateLim, P_LCNV_ExciterMinCurrent);
            if (Converter.Excitation.ControlData.ExcitationCurrentRef >= P_LCNV_ExciterMinCurrent)
            {
                V_LCNV_State_SubStep = 3;
            }
            break;
        }
        case 3:  // start PWM
        {
            for (i = 0; i < LCNV_GENCNV_CNT; i++)
            {
                if (Converter.GenConverter[i].ControlWord.Enable)
                {
                    Converter.GenConverter[i].ControlWord.PWM_Start = true;
                }
            }
            V_LCNV_State_SubStep = 4;
            break;
        }
        case 4:  // starting PWM
        {
            for (i = 0; i < LCNV_GENCNV_CNT; i++)
            {
                if (Converter.GenConverter[i].ControlWord.Enable && !Converter.GenConverter[i].StatusWord.PWM_Running)
                {
                    break;
                }
            }
            StateFunctionPointer = CNV_Gen_Running_State;   // started
            break;
        }
    }
    
    UpdateGridCommand(false);
    UpdateExcitationCommand(false);

    //-----------------------------------------------------------------------
    // EXIT CONDITIONS
    //-----------------------------------------------------------------------
    timer -= LCNV_SCAN_TIME;
    if (V_CNV_RequestedState == CNV_EM_STOP)
    {
        StateFunctionPointer = CNV_EmStop_State;
    }
    else if (timer <= 0)
    {
        ProcessTimeout_Flag = true;
        StateFunctionPointer = CNV_Fault_State;
    }
    else if (CnvFault_Count)
    {
        StateFunctionPointer = CNV_Fault_State;
    }
    else if (NotReady_Count)
    {
        StateFunctionPointer = CNV_NotReady_State;
    }
    else if (V_CNV_RequestedState <= CNV_GEN_STOPPING)
    {
        StateFunctionPointer = CNV_Gen_Stopping_State;   // STOP
    }
}




//***********************************************************************
// STATE : Generator running
//***********************************************************************
static void CNV_Gen_Running_State(S32 callMode)
{
    //-----------------------------------------------------------------------
    //ENTRY ACTION
    //-----------------------------------------------------------------------
    if (callMode == LCNV_STATE_CALLMODE_INIT)
    {
        V_CNV_State = CNV_GEN_RUNNING;
        strcpy(V_CNV_StateTxt, "Gen running");
        V_LCNV_State_SubStep = 0;
        UpdateGenCommand(true);
    }

    //-----------------------------------------------------------------------
    //CONTROL
    //-----------------------------------------------------------------------

    UpdateGridCommand(false);
    UpdateGenCommand(false);
    UpdateExcitationCommand(false);

    //-----------------------------------------------------------------------
    // EXIT CONDITIONS
    //-----------------------------------------------------------------------
    if (V_CNV_RequestedState == CNV_EM_STOP)
    {
        StateFunctionPointer = CNV_EmStop_State;
    }
    else if (CnvFault_Count)
    {
        StateFunctionPointer = CNV_Fault_State;
    }
    else if (NotReady_Count)
    {
        StateFunctionPointer = CNV_NotReady_State;
    }
    else if (V_CNV_RequestedState <= CNV_GEN_STOPPING)
    {
        StateFunctionPointer = CNV_Gen_Stopping_State;   // STOP
    }
    else if (V_CNV_RequestedState == CNV_PRODUCTION)
    {
        StateFunctionPointer = CNV_Production_State;
    }
    else if (V_CNV_RequestedState == CNV_MOTOR_RUNNING)
    {
        StateFunctionPointer = CNV_Motor_Running_State;
    }
}




