//_______________________________________________________________________
// Power setpoint correction auto learning functionality
//_______________________________________________________________________

#define CORRECTION_STEP_BIG 2
#define CORRECTION_STEP_SMALL 1

static S16 LearnCorrectionTable[NUM_OF_CNV_RPM_POINTS][NUM_OF_CNV_POWER_POINTS];


static void CloseLearnCorrectionTable()
{
    OS_Close(FileDescriptor_Cnv);
    OS_Release_File_User();
}

//learn correction value
static void LearnCorrectionValue()
{
    static U16 indexRpm;
    static U16 indexPower;
    static S16 deviation;

    // calculate rpm index
    if (V_ControllerRpm < 0) { return; }
    else if (V_ControllerRpm > MAX_TABLE_RPM) { return; }
    else { indexRpm = V_ControllerRpm / 50; }
    // calculate power index
    if (V_CNV_PowerSetpoint < 0) { return; }
    else if (V_CNV_PowerSetpoint > MAX_TABLE_POWER) { return; }
    else { indexPower = V_CNV_PowerSetpoint / 1000; }

    deviation = V_CNV_PowerSetpoint - V_LCNV_ActivePower_Generator;

    if (deviation > LearnCorrectionTable[indexRpm][indexPower])
    {
        // make smoother correction table by also slowly adjusting other values near the target value
        // check for array limits
        if (indexRpm > 0 && indexPower > 0)
        {
            if (LearnCorrectionTable[indexRpm - 1][indexPower - 1] <= LearnCorrectionTable[indexRpm][indexPower]) { LearnCorrectionTable[indexRpm - 1][indexPower - 1] += CORRECTION_STEP_SMALL; }
        }
        if (indexRpm > 0)
        {
            if (LearnCorrectionTable[indexRpm - 1][indexPower] <= LearnCorrectionTable[indexRpm][indexPower]) { LearnCorrectionTable[indexRpm - 1][indexPower] += CORRECTION_STEP_SMALL; }
        }
        if (indexPower > 0)
        {
            if (LearnCorrectionTable[indexRpm][indexPower - 1] <= LearnCorrectionTable[indexRpm][indexPower]) { LearnCorrectionTable[indexRpm][indexPower - 1] += CORRECTION_STEP_SMALL; }
        }
        if (indexRpm < NUM_OF_CNV_RPM_POINTS && indexPower < NUM_OF_CNV_POWER_POINTS)
        {
            if (LearnCorrectionTable[indexRpm + 1][indexPower + 1] <= LearnCorrectionTable[indexRpm][indexPower]) { LearnCorrectionTable[indexRpm + 1][indexPower + 1] += CORRECTION_STEP_SMALL; }
        }
        if (indexRpm < NUM_OF_CNV_RPM_POINTS)
        {
            if (LearnCorrectionTable[indexRpm + 1][indexPower] <= LearnCorrectionTable[indexRpm][indexPower]) { LearnCorrectionTable[indexRpm + 1][indexPower] += CORRECTION_STEP_SMALL; }
        }
        if (indexPower < NUM_OF_CNV_POWER_POINTS)
        {
            if (LearnCorrectionTable[indexRpm][indexPower + 1] <= LearnCorrectionTable[indexRpm][indexPower]) { LearnCorrectionTable[indexRpm][indexPower + 1] += CORRECTION_STEP_SMALL; }
        }

        LearnCorrectionTable[indexRpm][indexPower] += CORRECTION_STEP_BIG;
    }
    else if (deviation < LearnCorrectionTable[indexRpm][indexPower])
    {
        // make smoother correction table by also slowly adjusting other values near the target value
        // check for array limits
        if (indexRpm > 0 && indexPower > 0)
        {
            if (LearnCorrectionTable[indexRpm - 1][indexPower - 1] >= LearnCorrectionTable[indexRpm][indexPower]) { LearnCorrectionTable[indexRpm - 1][indexPower - 1] -= CORRECTION_STEP_SMALL; }
        }
        if (indexRpm > 0)
        {
            if (LearnCorrectionTable[indexRpm - 1][indexPower] >= LearnCorrectionTable[indexRpm][indexPower]) { LearnCorrectionTable[indexRpm - 1][indexPower] -= CORRECTION_STEP_SMALL; }
        }
        if (indexPower > 0)
        {
            if (LearnCorrectionTable[indexRpm][indexPower - 1] >= LearnCorrectionTable[indexRpm][indexPower]) { LearnCorrectionTable[indexRpm][indexPower - 1] -= CORRECTION_STEP_SMALL; }
        }
        if (indexRpm < NUM_OF_CNV_RPM_POINTS && indexPower < NUM_OF_CNV_POWER_POINTS)
        {
            if (LearnCorrectionTable[indexRpm + 1][indexPower + 1] >= LearnCorrectionTable[indexRpm][indexPower]) { LearnCorrectionTable[indexRpm + 1][indexPower + 1] -= CORRECTION_STEP_SMALL; }
        }
        if (indexRpm < NUM_OF_CNV_RPM_POINTS)
        {
            if (LearnCorrectionTable[indexRpm + 1][indexPower] >= LearnCorrectionTable[indexRpm][indexPower]) { LearnCorrectionTable[indexRpm + 1][indexPower] -= CORRECTION_STEP_SMALL; }
        }
        if (indexPower < NUM_OF_CNV_POWER_POINTS)
        {
            if (LearnCorrectionTable[indexRpm][indexPower + 1] >= LearnCorrectionTable[indexRpm][indexPower]) { LearnCorrectionTable[indexRpm][indexPower + 1] -= CORRECTION_STEP_SMALL; }
        }

        LearnCorrectionTable[indexRpm][indexPower] -= CORRECTION_STEP_BIG;
    }
}

