                        char ErrorDescriptionString[81];
                        snprintf(ErrorDescriptionString, sizeof(ErrorDescriptionString), "Cnv %u GS, %3u-%s", (i + 1), GS_ErrorByte[i][j], ERROR_CODES_GetDescription(&GS_ErrorByte[i][j]));
                        CustomLog_MakeEntry(CnvErrorLog, &ErrorDescriptionString);
