static void SystemStatus()
{
    NotReady_Count = 0;
    CnvFault_Count = 0;
    CnvWarning_Count = 0;

    GridCnvEnabled_Count = 0;
    GenCnvEnabled_Count = 0;

    int i;
    // GRID converter
    for (i = 0; i < LCNV_GRIDCNV_CNT; i++)
    {
        if (Converter.GridConverter[i].ControlWord.Enable)
        {
            GridCnvEnabled_Count++;

            if (Converter.GridConverter[i].StatusWord.Fault)
            {
                CnvFault_Count++;
            }
            if (Converter.GridConverter[i].StatusWord.Warning)
            {
                CnvWarning_Count++;
            }
            if (!Converter.GenConverter[i].StatusWord.Ready)
            {
                NotReady_Count++;
            }
        }
    }
    // GEN converter
    for (i = 0; i < LCNV_GENCNV_CNT; i++)
    {
        if (Converter.GenConverter[i].ControlWord.Enable)
        {
            GenCnvEnabled_Count++;

            if (Converter.GenConverter[i].StatusWord.Fault)
            {
                CnvFault_Count++;
            }
            if (Converter.GenConverter[i].StatusWord.Warning)
            {
                CnvWarning_Count++;
            }
            if (!Converter.GenConverter[i].StatusWord.Ready)
            {
                NotReady_Count++;
            }
        }
    }
    // excitation converter
    if (Converter.Excitation.StatusWord.Fault)
    {
        CnvFault_Count++;
    }
    if (Converter.Excitation.StatusWord.Warning)
    {
        CnvWarning_Count++;
    }
    if (!Converter.Excitation.StatusWord.Ready)
    {
        NotReady_Count++;
    }
    // general
    if (Converter.StatusWord.Fault)
    {
        CnvFault_Count++;
    }
    if (Converter.StatusWord.Warning)
    {
        CnvWarning_Count++;
    }
}



