// Conversion RPM to rad/s
static float Rpm_To_RadS(float inVal)
{
    return (inVal * (float)PI) / 30;
}



static void SimulatePowerTorque()
{
    F32 powerSP_kW = 0;
    F32 torque_kNm = 0;

    if (DLL_IN_Initialize)
    {
        V_CNV_PowerSetpoint = 0;
        FilterAvg_Reset(pwrSPavgFilt, 0/*resetValue*/);
    }

    switch (ControlAlgorithm)
    {
        case LCNV_POWER_CONTROL:

            powerSP_kW = FilterAvg_Control(pwrSPavgFilt, (V_CNV_PowerSetpoint / 10)/*Input*/);              // simulate converter delay
            powerSP_kW = powerSP_kW * ((F32)P_DLL_GenEfficiency / 100);          // include losses
            if (V_ControllerRpm > 0 && DLL_OUT_GenConnected)
            {
                torque_kNm = powerSP_kW / Rpm_To_RadS((F32)V_ControllerRpm / 1000);            // calculate torque SP
            }
            else
            {
                torque_kNm = 0;
            }

            break;

            //case LCNV_TORQUE_CONTROL:

            // just copy the setpoint values
            //V_CNV_TorqueActNm = V_TorqueSPNm;               // values in kNm
            //V_CNV_TorqueActPct = V_InverterTorqueRef;     // values in %

            //V_CNV_GridSide_ActivePower_Total = (V_CNV_TorqueActNm / 10) * Rpm_To_RadS( *AI_GeneratorRpm_value / 100 ) / 100;
            //break;
    }

    Converter.GenConverter[0].ControlData.ControlRef = powerSP_kW / 4;
    Converter.GenConverter[1].ControlData.ControlRef = Converter.GenConverter[0].StatusData.Active_Power;
    Converter.GenConverter[2].ControlData.ControlRef = Converter.GenConverter[0].StatusData.Active_Power;
    Converter.GenConverter[3].ControlData.ControlRef = Converter.GenConverter[0].StatusData.Active_Power;

    Converter.GenConverter[0].StatusData.Torque = torque_kNm / 4;
    Converter.GenConverter[1].StatusData.Torque = Converter.GenConverter[0].StatusData.Torque;
    Converter.GenConverter[2].StatusData.Torque = Converter.GenConverter[0].StatusData.Torque;
    Converter.GenConverter[3].StatusData.Torque = Converter.GenConverter[0].StatusData.Torque;

    Converter.GridConverter[0].StatusData.Active_Power = powerSP_kW;
}


#define LCNV_SIMU_GS_CONN_DELAY 5000
#define LCNV_SIMU_GS_DISCONN_DELAY 500
#define LCNV_SIMU_GS_PWMON_DELAY 1000
#define LCNV_SIMU_GS_PWMOFF_DELAY 500

static void SimulateGS(U8 unit)
{
    static int timer_1[LCNV_GRIDCNV_CNT];
    static int timer_2[LCNV_GRIDCNV_CNT];

    Converter.GridConverter[unit].StatusWord.Ready = Converter.GridConverter[unit].ControlWord.Enable;
    Converter.GridConverter[unit].StatusWord.Fault = false;
    Converter.GridConverter[unit].StatusWord.Warning = false;
    Converter.GridConverter[unit].StatusWord.Grid_OK = true;
    if (Converter.GridConverter[unit].StatusWord.Connected)
    {
        if (!Converter.GridConverter[unit].ControlWord.Connect)
        {
            timer_1[unit] -= LCNV_SCAN_TIME;
            if (timer_1[unit] <= 0)
            {
                Converter.GridConverter[unit].StatusWord.Connected = false;
                timer_1[unit] = LCNV_SIMU_GS_CONN_DELAY;
            }
        }
        else { timer_1[unit] = LCNV_SIMU_GS_DISCONN_DELAY; }
    }
    else
    {
        if (Converter.GridConverter[unit].ControlWord.Connect)
        {
            timer_1[unit] -= LCNV_SCAN_TIME;
            if (timer_1[unit] <= 0)
            {
                Converter.GridConverter[unit].StatusWord.Connected = true;
                timer_1[unit] = LCNV_SIMU_GS_DISCONN_DELAY;
            }
        }
        else { timer_1[unit] = LCNV_SIMU_GS_CONN_DELAY; }
    }

    if (Converter.GridConverter[unit].StatusWord.PWM_Running)
    {
        if (!Converter.GridConverter[unit].ControlWord.PWM_Start)
        {
            timer_2[unit] -= LCNV_SCAN_TIME;
            if (timer_2[unit] <= 0)
            {
                Converter.GridConverter[unit].StatusWord.PWM_Running = false;
                timer_2[unit] = LCNV_SIMU_GS_PWMON_DELAY;
            }
        }
        else { timer_2[unit] = LCNV_SIMU_GS_PWMOFF_DELAY; }
    }
    else
    {
        if (Converter.GridConverter[unit].ControlWord.PWM_Start)
        {
            timer_2[unit] -= LCNV_SCAN_TIME;
            if (timer_2[unit] <= 0)
            {
                Converter.GridConverter[unit].StatusWord.PWM_Running = true;
                timer_2[unit] = LCNV_SIMU_GS_PWMOFF_DELAY;
            }
        }
        else { timer_2[unit] = LCNV_SIMU_GS_PWMON_DELAY; }
    }

    Converter.GridConverter[unit].StatusWord.SelfDiagnosticActive = false;
    Converter.GridConverter[unit].StatusWord.ActiveParameterSet = Converter.GridConverter[unit].ControlWord.ParameterSet;
    Converter.GridConverter[unit].StatusWord.FRT_Detected = false;
    
    Converter.GridConverter[unit].StatusData.ErrorCode = 0;
    Converter.GridConverter[unit].StatusData.WarningCode = 0;
    Converter.GridConverter[unit].StatusData.Reactive_Power = 2;
    Converter.GridConverter[unit].StatusData.Apparent_Power = 3;
    Converter.GridConverter[unit].StatusData.PhaseToPhase_Voltage[0] = 600;
    Converter.GridConverter[unit].StatusData.PhaseToPhase_Voltage[1] = 601;
    Converter.GridConverter[unit].StatusData.PhaseToPhase_Voltage[2] = 602;
    Converter.GridConverter[unit].StatusData.DCLink_Voltage = 1001;
    Converter.GridConverter[unit].StatusData.Phase_Current[0] = 11;
    Converter.GridConverter[unit].StatusData.Phase_Current[1] = 12;
    Converter.GridConverter[unit].StatusData.Phase_Current[2] = 13;
    Converter.GridConverter[unit].StatusData.Grid_Frequency = 5001;
    
    Converter.GridConverter[unit].StatusData.Cabinet_Temperature = 123;
    Converter.GridConverter[unit].StatusData.Inductor_Temperature = 124;
    
    Converter.GridConverter[unit].StatusData.IsdOut = 11;
    Converter.GridConverter[unit].StatusData.IsqOut = 12;
    Converter.GridConverter[unit].StatusData.IsdRef = 13;
    Converter.GridConverter[unit].StatusData.IsqRef = 14;
    Converter.GridConverter[unit].StatusData.UsdRef = 15;
    Converter.GridConverter[unit].StatusData.UsqRef = 16;
    Converter.GridConverter[unit].StatusData.ActivePowerPhaseU = 17;
    Converter.GridConverter[unit].StatusData.ActivePowerPhaseV = 18;
    Converter.GridConverter[unit].StatusData.ActivePowerPhaseW = 19;
}

#define LCNV_SIMU_MS_PWMON_DELAY 1000
